import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { ResponsiveChartContainer, PieChart, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Balance {
  totalBudget: number;
  remaining: number;
}

interface SpendingCategory {
  name: string;
  value: number;
}

interface WidgetData {
  balance: Balance;
  spendingCategories: SpendingCategory[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { balance, spendingCategories } = widgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Monthly Budget
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50' }}>
              ${balance.totalBudget.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FF5722' }}>
              Remaining: ${balance.remaining.toLocaleString()}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: spendingCategories.map((category) => ({
                    name: category.name,
                    value: category.value,
                  })),
                  color: spendingCategories.map((_, index) => (index % 2 === 0 ? '#4CAF50' : '#FF5722')),
                },
              ]}
            >
              <ChartsClipPath id={clipPathId} />
              <PieChart />
            </ResponsiveChartContainer>
          </Box>

          <Grid container spacing={1}>
            {spendingCategories.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Typography variant="body2" sx={{ width: '100%', fontSize: '12px' }}>
                  {category.name}: ${category.value.toLocaleString()}
                </Typography>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
